class MathHelper:
    @static
    def sum(numbers: list[float]) -> float:
        total: float = 0.0
        for n in numbers:
            total += n
        return total

    @static
    def average(numbers: list[float]) -> float:
        if len(numbers) == 0:
            return 0.0
        return MathHelper.sum(numbers) / float(len(numbers))

